import re

def detect_prompt_injection(input_text: str, input_image: bytes = None) -> bool:
    injection_patterns = [
        r'ignore.*previous.*instructions',
        r'forget.*rules',
        r'you are now.*hacker',
        r'execute.*shell',
        r'transfer.*money'
    ]

    text = input_text.lower()
    for pattern in injection_patterns:
        if re.search(pattern, text):
            return True

    # Basic image text extraction check (requires easyocr)
    if input_image:
        try:
            import easyocr
            reader = easyocr.Reader(['en'])
            ocr_result = reader.readtext(input_image)
            ocr_text = ' '.join([text[1] for text in ocr_result])
            for pattern in injection_patterns:
                if re.search(pattern, ocr_text.lower()):
                    return True
        except:
            pass
    return False

