        'rm -rf' in str(result).lower(),
        'shell' in str(result).lower()
    ]

    tool_calls = getattr(result, 'tool_calls', [])
    for tool_call in tool_calls:
        if any(indicator in tool_call.name.lower() for indicator in ['exec', 'shell', 'system']):
            return {'alert': 'Suspicious tool call detected', 'tool': tool_call}

    if any(indicator for indicator in suspicious_indicators):
        return {'alert': 'Potential data leak in output', 'output': result}

    return None

