from agno import Agent

class SecureAgent(Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.sanitizer = InputSanitizer()

    def run(self, input_data):
        # Sanitize all inputs
        clean_input = self.sanitizer.clean(input_data)
        if not self.sanitizer.is_safe(clean_input):
            raise ValueError('Input rejected: potential injection detected')
        return super().run(clean_input)

class InputSanitizer:
    SAFE_COMMANDS = {'help', 'status', 'info'}

    def clean(self, data):
        if isinstance(data, str):
            return self._sanitize_text(data)
        elif isinstance(data, dict):
            return {k: self.clean(v) for k, v in data.items()}
        return data

    def _sanitize_text(self, text):
        # Remove common injection prefixes
        text = re.sub(r'(ignore|forget).*?instructions.*?[:;]', '', text, flags=re.IGNORECASE)
        return text

    def is_safe(self, data):
        text = str(data).lower()
        return not any(phrase in text for phrase in [
            'ignore previous',
            'new instructions',
            'system override'
        ])

from typing import List, Dict

class ToolValidator:
    APPROVED_TOOLS = {
        'search', 'calculator', 'weather', 'email_send'
    }

    @staticmethod
    def validate_tool_calls(tool_calls: List[Dict]) -> bool:
        for call in tool_calls:
            tool_name = call.get('name', '').lower()
            if tool_name not in ToolValidator.APPROVED_TOOLS:
                print(f'Blocked unauthorized tool: {tool_name}')
                return False

            # Validate parameters
            params = call.get('args', {})
            if ToolValidator._has_malicious_params(params):
                return False
        return True

    @staticmethod
    def _has_malicious_params(params):
        suspicious = ['rm', 'del', 'exec', 'curl', 'wget', 'bash']
        param_str = str(params).lower()
        return any(s in param_str for s in suspicious)

