from agno import Agent

class IsolatedAgent(Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.ephemeral_context = []

    def run(self, user_input):
        # Process in isolated context
        self.ephemeral_context.append({
            'role': 'user',
            'content': self._sanitize_input(user_input)
        })

        result = super().run(self.ephemeral_context[-1]['content'])

        # Discard ephemeral context after use
        self.ephemeral_context = []
        return result

    def _sanitize_input(self, input_data):
        if isinstance(input_data, str):
            # Strip role redefinition attempts
            return re.sub(
                r'^\s*(you are|pretend|act as|ignore).*?[:;.]',
                '',
                input_data,
                flags=re.IGNORECASE | re.MULTILINE
            )
        return input_data

